import{_ as t,o as e,c as l,a2 as r}from"./chunks/framework.DIMps2S2.js";const p=JSON.parse('{"title":"美股税表与股息税","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"compliance-and-tax/us-stock-tax.md","filePath":"zh-CN/compliance-and-tax/us-stock-tax.md"}'),o={name:"compliance-and-tax/us-stock-tax.md"};function i(n,a,s,h,c,d){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="美股税表与股息税" tabindex="-1">美股税表与股息税 <a class="header-anchor" href="#美股税表与股息税" aria-label="Permalink to &quot;美股税表与股息税&quot;">​</a></h1><p>美国税表类型选择、预扣股息税率及 W-8 更新流程。</p><h2 id="美国税表介绍" tabindex="-1">美国税表介绍 <a class="header-anchor" href="#美国税表介绍" aria-label="Permalink to &quot;美国税表介绍&quot;">​</a></h2><h3 id="w-8-表格" tabindex="-1">W-8 表格 <a class="header-anchor" href="#w-8-表格" aria-label="Permalink to &quot;W-8 表格&quot;">​</a></h3><p>W-8 是一个系列表格，用于证明收款人的外国人身份，告知付款方应适用的预扣税率。允许非美国居民根据与美国签订的税务协定申请降低或豁免预扣税。</p><ul><li><strong>W-8BEN</strong>：最常见版本，由外国个人填写，用于证明非美国税务居民身份并申请税务协定优惠，减少美国投资收入（如股息）的预扣税</li><li><strong>W-8BEN-E</strong>：适用于外国实体（公司、基金等），用途与 W-8BEN 类似</li></ul><h3 id="w-9-表格" tabindex="-1">W-9 表格 <a class="header-anchor" href="#w-9-表格" aria-label="Permalink to &quot;W-9 表格&quot;">​</a></h3><p>全称「要求纳税人识别号码及证明」，由需要向您付款的美国个人或企业发出，用于收集纳税人识别号码（TIN），如社会安全号码（SSN）或雇主识别号码（EIN）。</p><p>W-9 适用于美国公民或税务居民。</p><h3 id="_1099-表格" tabindex="-1">1099 表格 <a class="header-anchor" href="#_1099-表格" aria-label="Permalink to &quot;1099 表格&quot;">​</a></h3><p>系列表格，用于报告除常规工资薪水之外的各种非雇员收入：</p><ul><li><strong>1099-NEC</strong>：支付给独立承包商、自由职业者的报酬</li><li><strong>1099-MISC</strong>：杂项收入，如租金或版权费</li><li><strong>1099-DIV</strong>：股息和分配收入</li></ul><h3 id="如何选择" tabindex="-1">如何选择 <a class="header-anchor" href="#如何选择" aria-label="Permalink to &quot;如何选择&quot;">​</a></h3><ul><li>美国税务居民：提交 W-9 表格，付款方发出 1099 表格报告收入</li><li>非美国税务居民：提交 W-8 表格，证明外国身份并申请税务协定优惠</li></ul><h2 id="预扣分红股息税" tabindex="-1">预扣分红股息税 <a class="header-anchor" href="#预扣分红股息税" aria-label="Permalink to &quot;预扣分红股息税&quot;">​</a></h2><p>长桥依据税务协定为不同地区用户适用对应股息税率：</p><ul><li>中国区用户：10%（中美税务协定优惠税率）</li><li>非中国区用户：30%（美国标准预扣税率）<br> 部分特别税区可能适用不同税率，具体以实际收取为准。</li></ul><p>如需享受优惠税率，请确保 W-8BEN 表格中的税务信息准确并及时更新。</p><p><strong>W-8BEN 更新入口（SG 柜台）</strong>：长桥 App &gt; 资产 &gt; 全部功能 &gt; 开户资料，提交审核后通过全部功能 &gt; 更新文件 &gt; W-8BEN 查看最新状态。</p><p>W8 表格更新预计 2 周内生效。过往已扣除的股息税不予返还。</p><h2 id="重要提示" tabindex="-1">重要提示 <a class="header-anchor" href="#重要提示" aria-label="Permalink to &quot;重要提示&quot;">​</a></h2><p>作为金融机构，长桥不获允许提供税务或法律意见。如对税务身份或税率有疑问，请咨询专业税务顾问。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/compliance-and-tax">合规与税务</a></li></ul>',24)])])}const _=t(o,[["render",i]]);export{p as __pageData,_ as default};
